var elapsed = 0;
        return {
          draw: function(ctx, W, H, t, dt) {
            ctx.fillStyle = '#F5F0E8';
            ctx.fillRect(0, 0, W, H);

            // Grid
            ctx.strokeStyle = '#E0E0E0';
            ctx.lineWidth = 1;
            for (let i = 0; i <= 10; i++) {
              ctx.beginPath();
              ctx.moveTo(i * (W/10), 0);
              ctx.lineTo(i * (W/10), H);
              ctx.stroke();
              ctx.beginPath();
              ctx.moveTo(0, i * (H/10));
              ctx.lineTo(W, i * (H/10));
              ctx.stroke();
            }

            // Ball falling with acceleration (elapsed = real seconds since drop, resets on landing)
            const g = 9.8;
            const startY = 50;
            const groundY = H - 30;
            const clampedDt = Math.min(dt || 0, 0.05);
            elapsed += clampedDt;
            let yPos = startY + 0.5 * g * elapsed * elapsed;
            if (yPos >= groundY) {
              yPos = groundY;
              elapsed += clampedDt;
              if (elapsed > 1) { elapsed = 0; }
            }

            // Draw ball
            ctx.fillStyle = '#DC2626';
            ctx.beginPath();
            ctx.arc(W/2, yPos, 15, 0, Math.PI * 2);
            ctx.fill();

            // Position text
            ctx.fillStyle = '#333';
            ctx.font = '14px Arial';
            ctx.fillText('y = ½gt²', 10, 30);
            ctx.fillText('v = gt', 10, 50);

            // Velocity arrow
            const v = g * elapsed;
            const arrowLen = Math.min(v * 8, 100);
            ctx.strokeStyle = '#3B82F6';
            ctx.lineWidth = 2;
            ctx.beginPath();
            ctx.moveTo(W/2 + 30, yPos);
            ctx.lineTo(W/2 + 30, yPos + arrowLen);
            ctx.stroke();

            // Arrowhead
            ctx.beginPath();
            ctx.moveTo(W/2 + 30, yPos + arrowLen);
            ctx.lineTo(W/2 + 25, yPos + arrowLen - 10);
            ctx.lineTo(W/2 + 35, yPos + arrowLen - 10);
            ctx.closePath();
            ctx.fillStyle = '#3B82F6';
            ctx.fill();
          }
        };
